import pytest
from hypothesis import given, strategies as st, settings

from src.notifications.edit_handler import OnMessageEdited
from src.notifications.delete_handler import OnMessageDeleted
from src.notifications.surfaces import (
    PushSurface,
    InAppBannerSurface,
    SoundSurface,
    UnreadBadgeSurface,
)


def make_msg(mention_ids, version=1):
    return {"id": "M1", "mention_ids": list(mention_ids), "version": version}


# ─── REQ-005: edit adds a new mention ──────────────────────────────────────


def test_edit_adding_new_mention_triggers_fresh_mention_pipeline():
    """REQ-005: WHEN an edited message adds a mention of a previously-unmentioned
    member, the system SHALL treat the newly-added mention as equivalent to a
    fresh mention (applies REQ-001 — concurrent dispatch on all surfaces)."""
    before = make_msg(mention_ids=["U2"], version=1)
    after = make_msg(mention_ids=["U2", "U3"], version=2)

    dispatched_for = OnMessageEdited(before, after)
    # Only U3 is newly mentioned; U2 was already mentioned.
    assert dispatched_for == ["U3"]


def test_edit_not_changing_mention_set_does_not_retrigger():
    """REQ-005 (implicit converse): IF the edit does not change the mention set,
    no fresh dispatch fires. Closes the noise-amplification loophole."""
    before = make_msg(mention_ids=["U2"], version=1)
    after = make_msg(mention_ids=["U2"], version=2)  # body text changed elsewhere

    dispatched_for = OnMessageEdited(before, after)
    assert dispatched_for == []


def test_edit_added_mention_to_non_member_is_silently_skipped():
    """REQ-005 + REQ-003 composition: an edit that adds a mention of a
    non-member of the channel SHALL be silently skipped (REQ-003 rule
    composes with the fresh-mention treatment of REQ-005)."""
    before = make_msg(mention_ids=["U2"], version=1)
    after = make_msg(mention_ids=["U2", "OUTSIDER"], version=2)

    dispatched_for = OnMessageEdited(
        before, after, channel_members={"U1", "U2", "U3"}
    )
    assert dispatched_for == []  # OUTSIDER is not a member → silent skip


# ─── REQ-006: delete retracts in-app, leaves push/badge ────────────────────


def test_delete_retracts_in_app_banner_for_unopened_notification():
    """REQ-006: WHEN a message containing an @-mention is deleted before the
    mentioned member has opened the notification, the system SHALL retract the
    notification on surfaces that support retraction (in-app banner)."""
    msg = make_msg(mention_ids=["U2"])

    retracted = OnMessageDeleted(msg, opened_by={"U1"})  # U2 has not opened it
    assert InAppBannerSurface.__name__ in retracted["surfaces_retracted"]


def test_delete_leaves_push_unchanged():
    """REQ-006: non-retractable surfaces (push) SHALL be left in their
    pre-deletion state."""
    msg = make_msg(mention_ids=["U2"])

    retracted = OnMessageDeleted(msg, opened_by=set())
    assert PushSurface.__name__ not in retracted["surfaces_retracted"]


def test_delete_leaves_unread_badge_and_count_unchanged():
    """REQ-006: non-retractable surfaces (unread badge, unread count) SHALL be
    left in their pre-deletion state."""
    msg = make_msg(mention_ids=["U2"])

    retracted = OnMessageDeleted(
        msg, counters_before={"unread_badge_count": 5, "unread_mention_count": 2}
    )
    assert retracted["counters_after"]["unread_badge_count"] == 5
    assert retracted["counters_after"]["unread_mention_count"] == 2


def test_delete_after_target_opened_notification_is_a_noop():
    """REQ-006 boundary: 'before the mentioned member has opened the
    notification' — once opened, deletion does not retract the in-app banner."""
    msg = make_msg(mention_ids=["U2"])

    retracted = OnMessageDeleted(msg, opened_by={"U2"})
    assert retracted["surfaces_retracted"] == []


