@st.composite
def edit_revert_pairs(draw):
    base = draw(st.lists(st.sampled_from(["U2", "U3", "U4"]), min_size=1, max_size=3, unique=True))
    delta = draw(st.sampled_from(["U2", "U3", "U4", "U5"]))
    return base, delta


@given(pair=edit_revert_pairs())
@settings(max_examples=500, deadline=None)
def test_edit_then_revert_mention_set_is_reversible_with_no_duplicate_notifications(pair):
    """Property: reversible (REQ-005). Editing to add a mention then reverting
    to remove it again is a no-op for the dispatch ledger — no duplicate
    notifications are emitted to the briefly-added recipient."""
    base, extra = pair
    v1 = make_msg(mention_ids=base, version=1)
    if extra in base:
        v2 = make_msg(mention_ids=[m for m in base if m != extra], version=2)
        v3 = make_msg(mention_ids=base, version=3)
        added_then_reverted = OnMessageEdited(v1, v2) + OnMessageEdited(v2, v3)
        # we removed and re-added the same member; this is the reverse of the
        # "add then remove" case — depending on impl semantics, only the
        # readd is a fresh mention.
        assert added_then_reverted.count(extra) <= 1
    else:
        v2 = make_msg(mention_ids=base + [extra], version=2)
        v3 = make_msg(mention_ids=base, version=3)
        dispatched_forward = OnMessageEdited(v1, v2)
        dispatched_back = OnMessageEdited(v2, v3)
        # Forward dispatch fires once for `extra`; reverting does NOT fire a
        # second notification to `extra`. Combined ledger ≤ 1 for `extra`.
        ledger_for_extra = dispatched_forward.count(extra) + dispatched_back.count(extra)
        assert ledger_for_extra <= 1


@st.composite
def delete_sequences(draw):
    return draw(st.lists(st.sampled_from(["delete", "noop"]), min_size=1, max_size=10))


@given(seq=delete_sequences())
@settings(max_examples=500, deadline=None)
def test_delete_retraction_in_app_banner_invariant_no_un_retract(seq):
    """Property: invariant (REQ-006). Once an in-app banner is retracted via
    delete, no subsequent operation in the delete-handler path SHALL
    un-retract it (no surface flicker / resurrection)."""
    msg = make_msg(mention_ids=["U2"])
    banner_state = "visible"
    for op in seq:
        if op == "delete" and banner_state == "visible":
            result = OnMessageDeleted(msg, opened_by=set())
            if InAppBannerSurface.__name__ in result["surfaces_retracted"]:
                banner_state = "retracted"
        elif op == "delete" and banner_state == "retracted":
            result = OnMessageDeleted(msg, opened_by=set())
            # invariant: cannot un-retract from the delete-handler
            assert InAppBannerSurface.__name__ not in result.get("surfaces_re_shown", [])
    # final state must be either "visible" (no delete observed) or "retracted"
    assert banner_state in {"visible", "retracted"}


@given(prior_posters=st.lists(st.sampled_from(["U2", "U3", "U4", "U5"]), min_size=0, max_size=4, unique=True),
       target=st.sampled_from(["U2", "U3", "U4", "U5"]))
@settings(max_examples=500, deadline=None)
def test_in_thread_participation_boundary_only_prior_posters_receive_mentions(prior_posters, target):
    """Property: boundary (REQ-001 thread scope). The boundary is
    `target ∈ prior_posters`. Mentions to non-prior-posters in a thread SHALL
    be silently skipped; mentions to prior posters SHALL be delivered."""
    from src.notifications.filter import FilterIneligibleRecipients
    channel = {"id": "T1", "kind": "thread", "members": ["U1"] + list(prior_posters)}
    msg = {"mention_ids": [target], "mention_kind": "individual", "channel": "T1", "author": "U1"}
    target_member = {"id": target, "joined_channels": ["T1"], "dnd": {"manual_on": False, "schedule_window": None, "muted_channels": []}}

    filtered = FilterIneligibleRecipients(
        [target_member], msg, channel, thread_posters=set(prior_posters)
    )
    if target in prior_posters:
        assert filtered == [target_member]
    else:
        assert filtered == []
